    private fun handleIncomingIntent(intent: Intent?) {
        if (intent == null) {
            showError("No intent received.")
            return
        }

        when (intent.action) {
            Intent.ACTION_SEND -> {
                val mimeType = intent.type ?: ""
                when {
                    mimeType == "text/plain" -> handleSharedText(intent)
                    mimeType.startsWith("image/") -> handleSharedImage(intent)
                    else -> showError("Unsupported content type: $mimeType")
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                val mimeType = intent.type ?: ""
                if (mimeType.startsWith("image/")) {
                    handleSharedMultipleImages(intent)
                } else {
                    showError("Unsupported content type for multiple share: $mimeType")
                }
            }
            else -> {
                showError("Unsupported action: ${intent.action}")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)

        if (sharedText.isNullOrBlank()) {
            showError("No text content received.")
            return
        }

        val sanitizedText = sanitizeText(sharedText)

        if (sanitizedText.isBlank()) {
            showError("Received text was empty after sanitization.")
            return
        }

        val urls = extractUrls(sanitizedText)

        addLabel("Shared Text:")
        addTextContent(sanitizedText)

        if (urls.isNotEmpty()) {
            addLabel("Extracted URLs:")
            urls.forEach { url ->
                if (isValidUrl(url)) {
                    addTextContent(url)
                    processUrl(url)
                } else {
                    Log.w(TAG, "Skipping invalid URL: $url")
                }
            }
        }

        Toast.makeText(this, "Text content received successfully", Toast.LENGTH_SHORT).show()
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri == null) {
            showError("No image received.")
            return
        }

        if (!isValidContentUri(imageUri)) {
            showError("Invalid or insecure image URI.")
            return
        }

        addLabel("Shared Image:")
        processAndDisplayImage(imageUri)

        Toast.makeText(this, "Image received successfully", Toast.LENGTH_SHORT).show()
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (imageUris.isNullOrEmpty()) {
            showError("No images received.")
            return
        }

        val validUris = imageUris.filter { isValidContentUri(it) }.take(MAX_IMAGES)

        if (validUris.isEmpty()) {
            showError("No valid images received.")
            return
        }

        addLabel("Shared Images (${validUris.size}):")

        validUris.forEachIndexed { index, uri ->
            addLabel("Image ${index + 1}:")
            processAndDisplayImage(uri)
        }

        Toast.makeText(this, "${validUris.size} image(s) received successfully", Toast.LENGTH_SHORT).show()
    }

    private fun processAndDisplayImage(uri: Uri) {
        try {
            // Check file size first
            val fileSize = getContentSize(uri)
            if (fileSize > MAX_IMAGE_SIZE_BYTES) {
                addTextContent("Image too large (${fileSize / 1024 / 1024} MB). Max allowed: ${MAX_IMAGE_SIZE_BYTES / 1024 / 1024} MB.")
                return
            }

            // Decode bounds first to check dimensions without loading full image
            val options = BitmapFactory.Options().apply {
                inJustDecodeBounds = true
            }

            openInputStreamSafely(uri)?.use { inputStream ->
                BitmapFactory.decodeStream(inputStream, null, options)
            } ?: run {
                addTextContent("Unable to read image.")
                return
            }

            val imageWidth = options.outWidth
            val imageHeight = options.outHeight

            if (imageWidth <= 0 || imageHeight <= 0) {
                addTextContent("Invalid image dimensions.")
                return
            }

            // Calculate sample size for downscaling
            var sampleSize = 1
            while (imageWidth / sampleSize > MAX_IMAGE_DIMENSION || imageHeight / sampleSize > MAX_IMAGE_DIMENSION) {
                sampleSize *= 2
            }

            val decodeOptions = BitmapFactory.Options().apply {
                inSampleSize = sampleSize
            }

            val bitmap = openInputStreamSafely(uri)?.use { inputStream ->
                BitmapFactory.decodeStream(inputStream, null, decodeOptions)
            }

            if (bitmap != null) {
                val imageView = ImageView(this).apply {
                    layoutParams = LinearLayout.LayoutParams(
                        LinearLayout.LayoutParams.MATCH_PARENT,
                        600
                    ).apply {
                        setMargins(0, 8, 0, 16)
                    }
                    scaleType = ImageView.ScaleType.FIT_CENTER
                    setImageBitmap(bitmap)
                    contentDescription = "Shared image"
                }
                containerLayout.addView(imageView)

                addTextContent("Dimensions: ${options.outWidth}x${options.outHeight}, MIME: ${options.outMimeType ?: "unknown"}")

                processImage(uri, bitmap)
            } else {
                addTextContent("Failed to decode image.")
            }
        } catch (e: SecurityException) {
            Log.e(TAG, "Security exception reading image", e)
            addTextContent("Permission denied to read image.")
        } catch (e: Exception) {
            Log.e(TAG, "Error processing image", e)
            addTextContent("Error processing image.")
        }
    }

    private fun sanitizeText(text: String): String {
        val truncated = if (text.length > MAX_TEXT_LENGTH) {
            text.substring(0, MAX_TEXT_LENGTH)
        } else {
            text
        }
        // Remove null bytes and control characters except newlines and tabs
        return truncated.replace(Regex("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F]"), "").trim()
    }

    private fun extractUrls(text: String): List<String> {
        val matcher = Patterns.WEB_URL.matcher(text)
        val urls = mutableListOf<String>()
        while (matcher.find()) {
            matcher.group()?.let { url ->
                urls.add(url)
            }
        }
        return urls.distinct()
    }

    private fun isValidUrl(url: String): Boolean {
        return try {
            val uri = Uri.parse(url)
            val scheme = uri.scheme?.lowercase()
            (scheme == "http" || scheme == "https") && Patterns.WEB_URL.matcher(url).matches()
        } catch (e: Exception) {
            false
        }
    }

    private fun isValidContentUri(uri: Uri): Boolean {
        val scheme = uri.scheme?.lowercase()
        // Only allow content:// URIs for security - reject file:// to prevent path traversal
        if (scheme != "content") {
            Log.w(TAG, "Rejected URI with scheme: $scheme")
            return false
        }

        // Check for path traversal attempts
        val path = uri.path ?: return false
        if (path.contains("..") || path.contains("//")) {
            Log.w(TAG, "Rejected URI with suspicious path: $path")
            return false
        }

        // Verify we can actually resolve the content provider
        return try {
            contentResolver.getType(uri) != null
        } catch (e: SecurityException) {
            Log.w(TAG, "SecurityException checking URI type", e)
            false
        } catch (e: Exception) {
            Log.w(TAG, "Exception checking URI type", e)
            false
        }
    }

    private fun getContentSize(uri: Uri): Long {
